-- Automation node registry — expanded to 85 node types (canvas rebuild).
-- Idempotent upsert: mirrors src/lib/automation/node-registry.ts (build-time truth).

on conflict (node_type) do update set
  label = excluded.label, category = excluded.category, scope = excluded.scope,
  risk = excluded.risk, min_plan = excluded.min_plan, requires_approval = excluded.requires_approval,
  blocked_from_autorun = excluded.blocked_from_autorun, description = excluded.description, updated_at = now();
